Here's a simple implementation of the two microservices using Node.js with Express for the REST API and Axios for HTTP requests to check the NPM and GitHub APIs.

**Resty Microservice (Resty.js):**

```javascript
const express = require('express');
const axios = require('axios');
const app = express();
app.use(express.json());

app.post('/packages', async (req, res) => {
  const packages = req.body;
  if (!Array.isArray(packages) || packages.length !== 10) {
    return res.status(400).send('Invalid package list');
  }
  try {
    const healthResults = await checkPackageHealth(packages);
    res.json(healthResults);
  } catch (error) {
    res.status(500).send(error.message);
  }
});

async function checkPackageHealth(packages) {
  const healthResults = [];
  for (const pkg of packages) {
    const health = await checkPackageHealthForPackage(pkg);
    healthResults.push(health);
  }
  return healthResults;
}

async function checkPackageHealthForPackage(pkg) {
  const npmInfo = await axios.get(`https://registry.npmjs.org/${pkg}`);
  const githubInfo = await axios.get(`https://api.github.com/repos/${npmInfo.data.repository.url.split('/').slice(-2).join('/')}`);

  const lastVersionDate = new Date(npmInfo.data['dist-tags'].latest);
  const lastCommitDate = new Date(githubInfo.data.pushed_at);

  const isUpToDate = lastVersionDate > new Date(Date.now() - 30 * 24 * 60 * 60 * 1000);
  const hasMaintainers = npmInfo.data.maintainers && npmInfo.data.maintainers.length >= 2;
  const isRecentCommit = lastCommitDate > new Date(Date.now() - 14 * 24 * 60 * 60 * 1000);

  return {
    package: pkg,
    isUpToDate,
    hasMaintainers,
    isRecentCommit,
  };
}

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => console.log(`Resty listening on port ${PORT}`));
```

