        // Replace SQL WHERE with MongoDB filter
        mongoQuery = mongoQuery.replaceAll("WHERE\\s+", ", {");

        // Replace SQL AND with MongoDB $and
        mongoQuery = mongoQuery.replaceAll("AND\\s+", ", {");

        // Replace SQL OR with MongoDB $or
        mongoQuery = mongoQuery.replaceAll("OR\\s+", ", {");

        // Replace SQL LIKE with MongoDB $regex
        mongoQuery = mongoQuery.replaceAll("LIKE\\s+", "$regex: ");

        // Replace SQL = with MongoDB : 
        mongoQuery = mongoQuery.replaceAll("=", ":");

        // Replace SQL IN with MongoDB $in
        mongoQuery = mongoQuery.replaceAll("IN\\s*\\(", "$in: [");

        // Replace SQL NOT IN with MongoDB $nin
        mongoQuery = mongoQuery.replaceAll("NOT IN\\s*\\(", "$nin: [");

        // Replace SQL > with MongoDB $
        mongoQuery = mongoQuery.replaceAll(">", "$gt");

        // Replace SQL < with MongoDB $
        mongoQuery = mongoQuery.replaceAll("<", "$lt");

        // Replace SQL >= with MongoDB $
        mongoQuery = mongoQuery.replaceAll(">=", "$gte");

        // Replace SQL <= with MongoDB $
        mongoQuery = mongoQuery.replaceAll("<=", "$lte");

        // Replace SQL <> with MongoDB $ne
        mongoQuery = mongoQuery.replaceAll("<>|!=", "$ne");

        // Replace SQL IS NULL with MongoDB $exists
        mongoQuery = mongoQuery.replaceAll("IS NULL", "$exists: false");

        // Replace SQL IS NOT NULL with MongoDB $exists
        mongoQuery = mongoQuery.replaceAll("IS NOT NULL", "$exists: true");

        // Replace SQL ORDER BY with MongoDB sort
        mongoQuery = mongoQuery.replaceAll("ORDER BY\\s+", ".sort({");

        // Replace SQL ASC with MongoDB 1
