        mongoQuery = mongoQuery.replaceAll("DESC", "-1");

        // Replace SQL LIMIT with MongoDB limit
        mongoQuery = mongoQuery.replaceAll("LIMIT\\s+", ".limit(");

        // Close MongoDB query
        mongoQuery = mongoQuery.replaceAll("\\)\\s*;$", "});");

        return mongoQuery;
    }

