import threading
from math import sqrt

def is_prime(n):
    if n <= 1:
        return False
    if n <= 3:
        return True
    if n % 2 == 0 or n % 3 == 0:
        return False
    i = 5
    while i * i <= n:
        if n % i == 0 or n % (i + 2) == 0:
            return False
        i += 6
    return True

def sum_primes_in_subarray(subarray, limit):
    return sum(x for x in subarray if is_prime(x) and x <= limit)

def calculate_sums(subarrays, limit):
    results = []
    threads = []

    def thread_target(subarray, index):
        results[index] = sum_primes_in_subarray(subarray, limit)

    for i, subarray in enumerate(subarrays):
        thread = threading.Thread(target=thread_target, args=(subarray, i))
        threads.append(thread)
        thread.start()

    for thread in threads:
        thread.join()

    results.sort(reverse=True)
    return results

# Example usage:
limit = 100
subarrays = [(1, 10), (5, 15), (20, 30)]
print(calculate_sums(subarrays, limit))
